  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  padding: 20px;
  background: #1e1e2e;
  border-radius: 12px;
}

.demo > div {
  background: linear-gradient(135deg, #50fa7b, #8be9fd);
  color: black;
  padding: 30px;
