:root {
  /* 1. Primitive（原始值，不直接用） */
  --blue-50: #eff6ff;
  --blue-500: #3b82f6;
  --blue-900: #1e3a8a;
  --gray-50: #f9fafb;
  --gray-900: #111827;

  --space-1: 4px;
  --space-2: 8px;
  --space-4: 16px;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 16px;

  /* 2. Semantic（語意，給元件用） */
  --color-primary: var(--blue-500);
  --color-primary-hover: var(--blue-600);
  --color-text: var(--gray-900);
  --color-bg: var(--gray-50);
  --color-border: var(--gray-200);

